  1	import * as React from 'react';
  2	import { StatusBox } from '@odf/shared/generic/status-box';
  3	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
  4	import {
  5	  Table,
  6	  Tbody,
  7	  Td,
  8	  Th,
  9	  ThProps,
 10	  Thead,
 11	  Tr,
 12	} from '@patternfly/react-table';
 13	import { useSelectList } from '../hooks/select-list';
 14	import { useSortList } from '../hooks/sort-list';
 15	import { getUID } from '../selectors';
 16	import { useCustomTranslation } from '../useCustomTranslationHook';
 17	import { TableColumnProps, RowComponentType } from './composable-table';
 18	
 19	export enum TableVariant {
 20	  DEFAULT = 'default',
 21	  COMPACT = 'compact',
 22	}
 23	
 24	const hasNoDeletionTimestamp: IsRowSelectable = <T extends K8sResourceCommon>(
 25	  row: T
 26	) => !row?.metadata?.deletionTimestamp;
 27	
 28	const areAllRowsSelected = <T extends K8sResourceCommon>(
 29	  selectableRows: T[],
 30	  selectedRows: T[]
 31	) => {
 32	  const selectedRowIds = selectedRows?.map(getUID);
 33	  const selecteableRowsIds = selectableRows.map(getUID);
 34	  return (
 35	    selecteableRowsIds?.length &&
 36	    selecteableRowsIds.every((rowId) => selectedRowIds?.includes(rowId))
 37	  );
 38	};
 39	
 40	const isRowSelected = <T extends K8sResourceCommon>(
 41	  rowId: string,
 42	  selectedRows: T[]
 43	) => selectedRows.some((row) => getUID(row) === rowId);
 44	
 45	const canApplyInitialSort = (
 46	  columns: TableColumnProps[],
 47	  initialSortIndex: number
 48	): boolean => !!columns[initialSortIndex]?.sortFunction;
 49	
 50	export const SelectableTable: SelectableTableProps = <
 51	  T extends K8sResourceCommon,
 52	>({
 53	  selectedRows,
 54	  setSelectedRows,
 55	  columns,
 56	  rows,
 57	  RowComponent,
 58	  extraProps,
 59	  isColumnSelectableHidden,
 60	  loaded,
 61	  loadError,
 62	  emptyRowMessage,
 63	  initialSortColumnIndex,
 64	  borders,
 65	  className,
 66	  isRowSelectable,
 67	  variant,
 68	  selectionType = SelectionType.CHECKBOX,
 69	}: TableProps<T>) => {
 70	  const { t } = useCustomTranslation();
 71	
 72	  const {
 73	    onSort,
 74	    sortIndex: activeSortIndex,
 75	    sortDirection: activeSortDirection,
 76	    sortedData: sortedRows,
 77	  } = useSortList<T>(
 78	    rows,
 79	    columns,
 80	    false,
 81	    canApplyInitialSort(columns, initialSortColumnIndex)
 82	      ? initialSortColumnIndex
 83	      : -1
 84	  );
 85	
 86	  const [selectableRows, rowIds] = React.useMemo(() => {
 87	    const selectableRows =
 88	      sortedRows?.filter(isRowSelectable || hasNoDeletionTimestamp) || [];
 89	    const rowIds = new Set(selectableRows?.map(getUID));
 90	    return [selectableRows, rowIds];
 91	  }, [sortedRows, isRowSelectable]);
 92	
 93	  const { onSelect } = useSelectList<T>(
 94	    selectableRows,
 95	    rowIds,
 96	    false,
 97	    setSelectedRows
 98	  );
 99	
100	  const getSortParams = (columnIndex: number): ThProps['sort'] => ({
101	    sortBy: {
102	      index: activeSortIndex,
103	      direction: activeSortDirection,
104	    },
105	    onSort: onSort,
106	    columnIndex,
107	  });
108	
109	  return (
110	    <StatusBox
111	      loadError={loadError}
112	      loaded={loaded}
113	      EmptyMsg={emptyRowMessage}
114	      data={sortedRows}
115	      skeleton={<div className="loading-skeleton--table pf-v6-u-mt-lg" />}
116	    >
117	      <Table
118	        className={className}
119	        aria-label={t('Selectable table')}
120	        borders={borders}
121	        variant={
122	          variant !== TableVariant.DEFAULT ? TableVariant.COMPACT : undefined
123	        }
124	      >
125	        <Thead>
126	          <Tr>
127	            <Th
128	              {...(!isColumnSelectableHidden
129	                ? {
130	                    select: {
131	                      onSelect: onSelect,
132	                      isSelected: areAllRowsSelected(
133	                        selectableRows,
134	                        selectedRows
135	                      ),
136	                    },
137	                  }
138	                : {})}
139	              aria-label={t('Select all')}
140	            />
141	            {columns?.map((col, index) => (
142	              <Th
143	                {...(!!col?.thProps ? col.thProps : {})}
144	                {...(!!col?.sortFunction ? { sort: getSortParams(index) } : {})}
145	                key={col?.columnName as string}
146	                aria-label={col?.columnName as string}
147	              >
148	                {col?.columnName}
149	              </Th>
150	            ))}
151	          </Tr>
152	        </Thead>
153	        <Tbody>
154	          {sortedRows.map((row, rowIndex) => (
155	            <Tr key={getUID(row)}>
156	              <Td
157	                select={{
158	                  rowIndex,
159	                  onSelect: onSelect,
160	                  isSelected: isRowSelected(getUID(row), selectedRows),
161	                  isDisabled:
162	                    (!!isRowSelectable && !isRowSelectable(row)) ||
163	                    !hasNoDeletionTimestamp(row),
164	                  props: {
165	                    id: getUID(row),
166	                  },
167	                  variant: selectionType,
168	                }}
169	              />
170	              <RowComponent row={row} extraProps={extraProps} />
171	            </Tr>
172	          ))}
173	        </Tbody>
174	      </Table>
175	    </StatusBox>
176	  );
177	};
178	
179	export enum SelectionType {
180	  RADIO = 'radio',
181	  CHECKBOX = 'checkbox',
182	}
183	
184	type IsRowSelectable = <T extends K8sResourceCommon>(row: T) => boolean;
185	
186	type TableProps<T extends K8sResourceCommon> = {
187	  rows: T[];
188	  columns: TableColumnProps[];
189	  RowComponent: React.ComponentType<RowComponentType<T>>;
190	  selectedRows: T[];
191	  setSelectedRows: (selectedRows: T[]) => void;
192	  extraProps?: any;
193	  isColumnSelectableHidden?: boolean;
194	  loaded: boolean;
195	  loadError?: any;
196	  emptyRowMessage?: React.FC;
197	  initialSortColumnIndex?: number;
198	  /** Render borders */
199	  borders?: boolean;
200	  /** Additional classes added to the Table  */
201	  className?: string;
202	  isRowSelectable?: IsRowSelectable;
203	  variant?: TableVariant;
204	  selectionType?: SelectionType;
205	};
206	
207	type SelectableTableProps = <T extends K8sResourceCommon>(
208	  props: React.PropsWithoutRef<TableProps<T>>
209	) => ReturnType<React.FC>;

