160	                  isSelected: isRowSelected(getUID(row), selectedRows),
161	                  isDisabled:
162	                    (!!isRowSelectable && !isRowSelectable(row)) ||
163	                    !hasNoDeletionTimestamp(row),
164	                  props: {
165	                    id: getUID(row),
166	                  },
167	                  variant: selectionType,
168	                }}
169	              />
170	              <RowComponent row={row} extraProps={extraProps} />
171	            </Tr>
172	          ))}
173	        </Tbody>
174	      </Table>
175	    </StatusBox>
176	  );
177	};
178	
179	export enum SelectionType {
180	  RADIO = 'radio',
181	  CHECKBOX = 'checkbox',
182	}
183	
